INSERT INTO training_records (employee_id, training_type_id, completion_date, expiration_date, source)
SELECT e.id, sr.training_type_id, sr.completion_date, sr.expiration_date, 'phs'
FROM source_rows sr
JOIN employees e ON (
  (lower(e.last_name) = lower(sr.last_name) AND lower(e.first_name) = lower(sr.first_name))
  OR e.aliases @> ARRAY[sr.full_name]::text[]
)
ON CONFLICT (employee_id, training_type_id, completion_date) DO NOTHING;